prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Find all paths from Kaufwunsch and check for gateways that might create alternative routes
SELECT ?elem ?elemName ?elemType ?sourceName ?targetName WHERE {
  ?kaufwunsch a bboExt:ChoreographyTask .
  ?kaufwunsch bbo:name "Kaufwunsch" .

  # Get all nodes reachable from Kaufwunsch
  ?kaufwunsch ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?elem .

  ?elem a ?elemType .
  OPTIONAL { ?elem bbo:name ?elemName . }

  # Check for gateways in the path
  FILTER(?elemType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))

  OPTIONAL {
    ?edge a bbo:SequenceFlow .
    ?edge bbo:has_sourceRef ?elem .
    ?edge bbo:has_targetRef ?target .
    OPTIONAL { ?target bbo:name ?targetName . }
  }

  OPTIONAL {
    ?edge2 a bbo:SequenceFlow .
    ?edge2 bbo:has_targetRef ?elem .
    ?edge2 bbo:has_sourceRef ?source .
    OPTIONAL { ?source bbo:name ?sourceName . }
  }
}
LIMIT 50
